---@class LxMain
local LxMain = classX("LxMain", nil)

local PJXCenter = PJXCenter
local PJXGameMgr = PJXCenter.GameMgr
local PJXLuaMgr = PJXCenter.LuaMgr
local UnityEngine = UnityEngine

function LxMain:Initialize(isReload)
    LogWarn("Main Start Initialize ...")

    self:InitBackgroundLoading()
    self:InitLuaBinder()
    self:InitRandom()
    self:InitGameSetting()
    self:InitManager()
    self:InitBatchTask(function()
        LogWarn("Main InitializeOK ...")
        self:Enter(isReload)
    end)
end

function LxMain:Enter(isReload)
    gLxPatchCtrl:SetReload(isReload)
    if LGameSettings.isLoginAfter then
        gprint("isLoginLoadFont：", LGameSettings.isLoginLoadFont)
        if LGameSettings.isLoginLoadFont then
            gLxPatchCtrl:OnPrepareLevelOk()
            gLxPatchCtrl:OnPrepareUIOk()
        else
            gLGameLogin:DealFont(function()
                gLxPatchCtrl:OnPrepareLevelOk()
                gLxPatchCtrl:OnPrepareUIOk()
            end)
        end
        return
    end
    if isReload then
        --热更之后
        --恢复Lua环境
        MgrCenter.LevelMgr:SetCurrentLevelName(LevelNames.Update)
        gLxPatchCtrl:ReloadEnter()

    else
        MgrCenter.LevelMgr:LoadLevel(LevelNames.Update)
    end
end

---@region  BatchTask
function LxMain:InitBatchTask(excOk)
    --LNativeHelper.CallMethod(LNativeMethod.GameReady)
    GAME_READY_TIME = Time.realtimeSinceStartup

    self:ClearPreloadRes()

    ---@type LxPreloadRes
    self._preloadRes = require("LApp.resource.LxPreloadRes"):New()

    ---@type LxBatchTask
    local batchTask = self._batchTask
    if not batchTask  then
        batchTask = require("LApp.component.task.LxBatchTask"):New()
        batchTask:Initialize()
    end
    batchTask:InitBatchTask(nil, nil, function()
        excOk()
    end, nil)
    batchTask:AddBatchTask("PreLoad", "", self.InitPreload, self)
    batchTask:AddBatchTask("WarmUpShader", "", self.WarmUpShader, self)
    batchTask:AddBatchTask("InitTmpSetting", "", self.InitTmpSetting, self)
    --batchTask:AddBatchTask("SetFallbackSprite", "", self.InitFallbackSprite, self)
    --batchTask:AddBatchTask("SetFallbackFont", "", self.InitFallbackFont, self)
    --batchTask:AddBatchTask("InitGray", "", self.InitGray, self)
    batchTask:AddBatchTask("InitSpineDefaultMat", "", self.InitSpineDefaultMat, self)
    batchTask:AddBatchTask("InitSpineGrayMat", "", self.InitSpineGrayMat, self)
    batchTask:AddBatchTask("InitUiGrayMat", "", self.InitUiGrayMat, self)
    batchTask:AddBatchTask("InitSpriteDefaultMat", "", self.InitSpriteDefaultMat, self)
    batchTask:AddBatchTask("InitSpriteGrayMat", "", self.InitSpriteGrayMat, self)
    batchTask:AddBatchTask("InitPostShaders", "", self.InitPostShaders, self)

    batchTask:StartBatchTask()
end

function LxMain:InitPostShaders(exeOk, actionObj)
    CS.PostUtility.ClearShaders()
    self._preloadRes:LoadPostShaders(function(obj)
        exeOk(actionObj)
    end, function(obj)
        if obj == nil then
            if LOG_ERROR_ENABLED then
                LogError("shader post not found ...")
            end
        else
            CS.PostUtility.AddShader(obj)
        end
    end)
end

