function LxMain:InitGray(exeOk, actionObj)
    self._preloadRes:LoadMainShader(function(obj)
        if obj == nil then
            if LOG_ERROR_ENABLED then
                LogError("UIGray shader not found ...")
            end
            exeOk(actionObj)
            return
        end
        local shader = obj
        local collect = UnityEngine.ShaderVariantCollection.New()
        local variant = UnityEngine.ShaderVariantCollection.ShaderVariant.New()
        variant.shader = shader
        collect:Add(variant)
        collect:WarmUp()
        LxResUtil.InitUiGrayMaterial(shader)
        exeOk(actionObj)
    end)
end

function LxMain:InitFallbackSprite(exeOk, actionObj)
    PJXGameMgr:RegTmpSpriteAssetRequest()
    PJXGameMgr:ChangeTmpFallbackSprite(0)
    self._preloadRes:LoadMainFallbackSprite(function(obj)
        if obj == nil then
            if LOG_ERROR_ENABLED then
                LogError("Fonts/default/Art/ChatFace.asset not found ...")
            end
            exeOk(actionObj)
            return
        end
        PJXGameMgr:ChangeTmpFallbackSprite(1, obj)
        exeOk(actionObj)
    end)
end

function LxMain:InitFallbackFont(exeOk, actionObj)
    PJXGameMgr:ChangeTmpFallbackFont(0)
    self._preloadRes:LoadMainFallbackFont(function(obj)
        if obj == nil then
            if LOG_ERROR_ENABLED then
                local fontName = self._preloadRes:GetLngFontName()
                LogError(tostring(fontName).." not found ...")
            end
            exeOk(actionObj)
            return
        end
        PJXGameMgr:ChangeTmpFallbackFont(1, obj)
        exeOk(actionObj)
    end)
end

