    end)
end

function LxMain:WarmUpShader(exeOk, actionObj)
    self._preloadRes:LoadMainGameShaderVariants(function(obj)
        if obj == nil then
            if LOG_ERROR_ENABLED then
                LogError("Builtin/GameShaderVariants.shadervariants not found ...")
            end
            exeOk(actionObj)
            return
        end

        obj:WarmUp()

        exeOk(actionObj)
    end)
end

function LxMain:InitPreload(excOk, actionObj)
    self._preloadRes:EnterMainPreload(excOk, actionObj)
end
