function LxMain:InitBackgroundLoading()
    UnityEngine.Application.backgroundLoadingPriority = UnityEngine.ThreadPriority.Low
end

function LxMain:InitLuaBinder()
    PJXLuaMgr:SetGameLuaTable(require("LApp.LxLuaBinder"):New())
end

function LxMain:InitRandom()
    PJXUtil.InitRandom(tonumber(tostring(PJXUtil.GetTime())) or math.floor(PJXUtil.GetTimeSeconds() * 1000))
    math.newrandomseed(PJXUtil.GetTimeSeconds() * 1000)
end

function LxMain:InitGameSetting()
    local isOk
    isOk = LGameSettings.InitGameSettings()
    if not isOk then
        error("initialize GameSetting fail ...")
    end

    isOk = LPlayerPrefs.InitializePrefs()
    if not isOk then
        error("Initialize PlayerPrefs fail ...")
    end

    self:InitUuid()
end

function LxMain:InitUuid()
    if not string.isempty(LPlayerPrefs.uuidFirstBoot) then return end
    LPlayerPrefs.SetUuidFirstBoot(PJXUtil.NewGUID("N")) --UnityEngine.SystemInfo.deviceUniqueIdentifier
    PJXGameMgr:SetGameEnvVar("new_uuid", "true")
    if LOG_INFO_ENABLED then
        printInfo("Main", "--->>> new uuid %s", LPlayerPrefs.uuidFirstBoot)
    end
end

function LxMain:InitManager()
    ---@type LxMgrCenter
    gLxMgrCenter = require("LApp.LxMgrCenter"):New()
    gLxMgrCenter:Initialize()

    ---@type LSdkImpl
    gLSdkImpl = require("LApp.sdk.LSdkImpl"):New()
    gLSdkImpl:Initialize()

    gLxServerList = require("LApp.LxServerList"):New()

    ---@type LxTKData
    gLxTKData = require("LApp.LxTKData"):new()
    gLxTKData:Initialize()

    gLxPatchCtrl = require("LApp.Patch.LxPatchCtrl"):New()

    gLxRestartCtrl = require("LApp.Patch.LxRestartCtrl"):New()
    gLxRestartCtrl:Initialize()

    MgrCenter.GameMgr:InitGame()
end

function LxMain:DisposeManager()
    if gLxMgrCenter then
        gLxMgrCenter:Dispose()
        gLxMgrCenter = nil
    end
end

function LxMain:ClearPreloadRes()
    if self._preloadRes then
        self._preloadRes:Dispose()
        self._preloadRes = nil
    end
end

---@return LxPreloadRes
function LxMain:GetPreloadRes()
    return self._preloadRes
end

function LxMain:Exit()
    self:ClearPreloadRes()
    PJXLuaMgr:SetGameLuaTable(nil)

    if gLSdkImpl then
        gLSdkImpl:Dispose()
        gLSdkImpl = nil
    end

    if gLxPatchCtrl then
        gLxPatchCtrl:Dispose()
        gLxPatchCtrl = nil
    end

    if gLxRestartCtrl then
        gLxRestartCtrl:Dispose()
        gLxRestartCtrl = nil
    end

    if gLxServerList then
        gLxServerList:Dispose()
        gLxServerList = nil
    end

    if gLxTKData then
        gLxTKData:Dispose()
        gLxTKData = nil
    end

    self:DisposeManager()

    LxTimer.ClearTimer()
end

return LxMain